import{_ as e,o as a,c as l,a7 as n}from"./chunks/framework.C5fSpjcB.js";const x=JSON.parse('{"title":"密契（Covenants）概要","description":"","frontmatter":{},"headers":[],"relativePath":"ja/covenants/index.md","filePath":"ja/covenants/index.md","lastUpdated":1775394001000}'),i={name:"ja/covenants/index.md"};function r(s,t,o,d,h,c){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="密契-covenants-概要" tabindex="-1">密契（Covenants）概要 <a class="header-anchor" href="#密契-covenants-概要" aria-label="Permalink to &quot;密契（Covenants）概要&quot;">​</a></h1><p><strong>密契</strong>は全覚醒体共通で装備可能な汎用装備システムです。運命の輪がキャラクター専用であるのに対し、密契はどの覚醒体にも自由に装備できます。</p><h2 id="基本情報" tabindex="-1">基本情報 <a class="header-anchor" href="#基本情報" aria-label="Permalink to &quot;基本情報&quot;">​</a></h2><ul><li>密契はすべての覚醒体に装備可能な汎用装備</li><li>複数の密契を同時に装備できる（スロット制）</li><li>ステータスボーナスやセット効果を付与</li></ul><h2 id="セット効果" tabindex="-1">セット効果 <a class="header-anchor" href="#セット効果" aria-label="Permalink to &quot;セット効果&quot;">​</a></h2><p>同じ系統の密契を複数装備することでセット効果が発動します。</p><table tabindex="0"><thead><tr><th style="text-align:center;">セット数</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:center;">2セット</td><td style="text-align:left;">基本セット効果発動</td></tr><tr><td style="text-align:center;">4セット</td><td style="text-align:left;">強化セット効果発動</td></tr></tbody></table><h2 id="密契の種類" tabindex="-1">密契の種類 <a class="header-anchor" href="#密契の種類" aria-label="Permalink to &quot;密契の種類&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">系統</th><th style="text-align:left;">主な効果</th><th style="text-align:left;">推奨ロール</th></tr></thead><tbody><tr><td style="text-align:left;"><em>準備中...</em></td><td style="text-align:left;">—</td><td style="text-align:left;">—</td></tr></tbody></table><h2 id="入手方法" tabindex="-1">入手方法 <a class="header-anchor" href="#入手方法" aria-label="Permalink to &quot;入手方法&quot;">​</a></h2><ul><li><strong>調査行動（Investigation）</strong> — ドロップ報酬</li><li><strong>チャレンジステージ</strong> — 高レアリティ密契が入手可能</li><li><strong>冶錬室</strong> — 不要な密契を変換</li><li><strong>ショップ</strong> — 通貨で交換</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>密契のサブステータスは厳選が重要です。メインステータスだけでなくサブステの組み合わせも確認しましょう。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./list.html">密契一覧</a></li><li><a href="./../wheels/">運命の輪概要</a></li><li><a href="./../engravings/">刻印概要</a></li><li><a href="./../awakeners/">覚醒体図鑑</a></li></ul>',14)])])}const g=e(i,[["render",r]]);export{x as __pageData,g as default};
